import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

export default function Internship() {
  const navigate = useNavigate();
  const [internships, setInternships] = useState([]);
  const [newInternship, setNewInternship] = useState({
    title: "",
    company: "",
    description: "",
  });

  const user = JSON.parse(localStorage.getItem("loggedInUser"));
  const role = user?.role;

  const isStudent = role === "Student";
  const isHR = role === "HR";
  const isAdmin = role === "Admin";

  useEffect(() => {
    const storedInternships = JSON.parse(localStorage.getItem("internships")) || [];
    setInternships(storedInternships);
  }, []);

  const handleAdd = () => {
    if (!newInternship.title || !newInternship.company || !newInternship.description) {
      alert("Please fill all fields");
      return;
    }

    const updated = [
      ...internships,
      { id: Date.now(), ...newInternship },
    ];

    setInternships(updated);
    localStorage.setItem("internships", JSON.stringify(updated));
    setNewInternship({ title: "", company: "", description: "" });
  };

  const handleDelete = (id) => {
    const updated = internships.filter((i) => i.id !== id);
    setInternships(updated);
    localStorage.setItem("internships", JSON.stringify(updated));
  };

  const handleEdit = (id) => {
    const updatedTitle = prompt("Enter new title");
    const updatedCompany = prompt("Enter new company");
    const updatedDescription = prompt("Enter new description");

    const updated = internships.map((i) =>
      i.id === id
        ? {
            ...i,
            title: updatedTitle || i.title,
            company: updatedCompany || i.company,
            description: updatedDescription || i.description,
          }
        : i
    );

    setInternships(updated);
    localStorage.setItem("internships", JSON.stringify(updated));
  };

  return (
    <div className="p-6 max-w-4xl mx-auto">
      <h1 className="text-3xl font-bold mb-4">Internship Opportunities</h1>

      {/* Admin or HR can add */}
      {(isHR || isAdmin) && (
        <div className="mb-6 space-y-2">
          <input
            type="text"
            placeholder="Title"
            value={newInternship.title}
            onChange={(e) => setNewInternship({ ...newInternship, title: e.target.value })}
            className="w-full px-3 py-2 border rounded"
          />
          <input
            type="text"
            placeholder="Company"
            value={newInternship.company}
            onChange={(e) => setNewInternship({ ...newInternship, company: e.target.value })}
            className="w-full px-3 py-2 border rounded"
          />
          <textarea
            placeholder="Description"
            value={newInternship.description}
            onChange={(e) => setNewInternship({ ...newInternship, description: e.target.value })}
            className="w-full px-3 py-2 border rounded"
          ></textarea>
          <button
            onClick={handleAdd}
            className="bg-green-600 text-white px-4 py-2 rounded hover:bg-green-700"
          >
            Add Internship
          </button>
        </div>
      )}

      {/* Internship List */}
      {internships.length === 0 ? (
        <p className="text-gray-500">No internships available.</p>
      ) : (
        <div className="space-y-4">
          {internships.map((item) => (
            <div key={item.id} className="border p-4 rounded shadow-sm bg-white">
              <h2 className="text-xl font-semibold">{item.title}</h2>
              <p className="text-sm text-gray-600">Company: {item.company}</p>
              <p className="mt-2">{item.description}</p>

              {/* Admin-only controls */}
              {isAdmin && (
                <div className="mt-3 space-x-2">
                  <button
                    onClick={() => handleEdit(item.id)}
                    className="px-3 py-1 bg-yellow-500 text-white rounded hover:bg-yellow-600"
                  >
                    Edit
                  </button>
                  <button
                    onClick={() => handleDelete(item.id)}
                    className="px-3 py-1 bg-red-600 text-white rounded hover:bg-red-700"
                  >
                    Delete
                  </button>
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
